mapper.select:
SELECT TASK_ID, TASK_TITLE, TASK_CONTENT, PRIORITY, DUE_DATE, USER_ID, CATEGORY_ID, STATUS, TASK_STATUS, CREATED_DATE, UPDATED_DATE FROM TASK WHERE USER_ID = #{userId} AND STATUS <> 'DELETED'
AND DUE_DATE IS NOT NULL AND DUE_DATE >= TRUNC(SYSDATE) AND DUE_DATE < TRUNC(SYSDATE) + 1
AND DUE_DATE IS NOT NULL AND DUE_DATE < TRUNC(SYSDATE) AND TASK_STATUS != 'DONE'
AND CATEGORY_ID = #{categoryId}
AND TASK_STATUS = #{taskStatus}
ORDER BY TASK_ID DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM TASK WHERE USER_ID = #{userId} AND STATUS <> 'DELETED'
AND DUE_DATE IS NOT NULL AND DUE_DATE >= TRUNC(SYSDATE) AND DUE_DATE < TRUNC(SYSDATE) + 1
AND DUE_DATE IS NOT NULL AND DUE_DATE < TRUNC(SYSDATE) AND TASK_STATUS != 'DONE'
AND CATEGORY_ID = #{categoryId}
AND TASK_STATUS = #{taskStatus}
